#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    void merge(vector<int>& nums1, int m, vector<int>& nums2, int n) {
        int i = m - 1;
        int j = n - 1;
        int k = m + n - 1;
        while (i >= 0 && j >= 0) {
            if (nums1[i] > nums2[j]) {
                nums1[k--] = nums1[i--];
            } else {
                nums1[k--] = nums2[j--];
            }
        }
        while (j >= 0) {
            nums1[k--] = nums2[j--];
        }
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    vector<int> tokens;
    int val;
    while (cin >> val) {
        tokens.push_back(val);
    }
    if (tokens.empty()) return 0;
    int m = tokens[0];
    int n = (tokens.size() - m - 2) / 2;
    vector<int> nums1(tokens.begin() + 1, tokens.begin() + 1 + m + n);
    vector<int> nums2(tokens.begin() + 2 + m + n, tokens.end());
    Solution sol;
    sol.merge(nums1, m, nums2, n);
    for (int i = 0; i < nums1.size(); i++) {
        cout << nums1[i] << (i == nums1.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
